The `agentErrorPostReceive`, `searchErrorPostReceive` and `embeddingsErrorPostReceive` are all identical except for the docs url, let's reduce the code duplication with a generic error handler. for example (I've cleaned up the code a bit with destructuging. Also no idea why status Code is converted to a string all over our code base, that should not be needed):

```ts
const createErrorHandler = (description: string) =>
	async function searchErrorPostReceive(
		this: IExecuteSingleFunctions,
		data: INodeExecutionData[],
		{ statusCode, body, statusMessage }: IN8nHttpFullResponse,
	): Promise<INodeExecutionData[]> {
		if (statusCode >= 400 && statusCode <= 599) {
			const errorBody = body as JsonObject;
			const error = (errorBody?.error ?? errorBody) as JsonObject;
			const errorMessage =
				typeof error.message === 'string'
					? error.message
					: (statusMessage ?? 'An unexpected issue occurred');

			throw new NodeApiError(this.getNode(), errorBody, {
				message: errorMessage,
				description,
			});
		}
		return data;
	};

export const agentErrorPostReceive = createErrorHandler(
	'Refer to the Agent API documentation at https://docs.perplexity.ai/api-reference/agent-post for valid parameters.',
);

